Test file: src/game-of-life.spec.ts
Implementation file: src/game-of-life.ts
Passing tests: 7
Recent changes: Added reproduction logic — gathering dead cell candidates (neighbors of live cells that aren't alive), filtering to those with exactly 3 live neighbors, combining survivors + births.

Current implementation:
```typescript
const isNeighbor = (cell: number[], other: number[]): boolean =>
  !(other[0] === cell[0] && other[1] === cell[1]) &&
  Math.abs(other[0] - cell[0]) <= 1 &&
  Math.abs(other[1] - cell[1]) <= 1;

const countNeighbors = (cell: number[], liveCells: number[][]): number =>
  liveCells.filter((other) => isNeighbor(cell, other)).length;

export function nextGeneration(liveCells: number[][]): number[][] {
  const survivors = liveCells.filter((cell) => {
    const neighborCount = countNeighbors(cell, liveCells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const deadCandidates: number[][] = [];
  for (const cell of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate = [cell[0] + dx, cell[1] + dy];
        if (
          !liveCells.some((c) => c[0] === candidate[0] && c[1] === candidate[1]) &&
          !deadCandidates.some((c) => c[0] === candidate[0] && c[1] === candidate[1])
        ) {
          deadCandidates.push(candidate);
        }
      }
    }
  }

  const births = deadCandidates.filter(
    (cell) => countNeighbors(cell, liveCells) === 3
  );

  return [...survivors, ...births];
}
```

Key things to evaluate:
- The dead candidate gathering logic is imperative with nested loops and mutable array. Could it be cleaner?
- The duplicate checking with .some() is repeated. Could a Set-based approach be cleaner?
- Naming: `deadCandidates` vs `candidateCells` etc.

EXPERIMENT MODE: Run autonomously, proceed to next test after completion.

